function solve(n: number): number {
    // Check if a number is a palindrome
    function isPalindrome(num: number): boolean {
        const str = num.toString();
        return str === str.split('').reverse().join('');
    }

    // Check if a number is a special number
    function isSpecial(num: number): boolean {
        const str = num.toString();
        const count: Record<string, number> = {};
        for (const ch of str) {
            const digit = parseInt(ch, 10);
            if (count[digit] === digit) {
                return false;
            }
            count[digit] = (count[digit] || 0) + 1;
        }
        return true;
    }

    // Generate the next special number
    let candidate = n + 1;
    while (true) {
        if (isPalindrome(candidate) && isSpecial(candidate)) {
            return candidate;
        }
        candidate++;
    }
}

